const AE_IMG = "data:image/png;base64,";
const MERCH_IMG = "data:image/png;base64,";
const DESIGNER_IMG = "data:image/png;base64,";

const WF_W = 1080, WF_H = 1440;
const WFC = {
  bg: "#eef1f7", ink: "#1b2440", sub: "#7e8aa8",
  blue: "#2f6bf6", blueSoft: "#e8f0ff",
  purple: "#7b5cff", purpleSoft: "#efeaff",
  green: "#16a364", greenSoft: "#e4f6ed",
  navy: "#141b2d", navy2: "#202c49", red: "#ff4d5e",
};
const WF_FONT = "'Inter', system-ui, sans-serif";

type Pt = [number, number];
const clampN = (v: number, a: number, b: number) => Math.max(a, Math.min(b, v));
const ramp = (t: number, a: number, b: number) => clampN((t - a) / (b - a), 0, 1);
const bump = (t: number, a: number, b: number, c: number, d: number) =>
  clampN((t - a) / (b - a), 0, 1) * (1 - clampN((t - c) / (d - c), 0, 1));

const wfPolyLen = (pts: Pt[]) => {
  const s: number[] = []; let tot = 0;
  for (let i = 0; i < pts.length - 1; i++) {
    const l = Math.hypot(pts[i + 1][0] - pts[i][0], pts[i + 1][1] - pts[i][1]);
    s.push(l); tot += l;
  }
  return { s, tot };
};
const wfPoint = (pts: Pt[], p: number): Pt => {
  const { s, tot } = wfPolyLen(pts);
  let d = clampN(p, 0, 1) * tot;
  for (let i = 0; i < s.length; i++) {
    if (d <= s[i] || i === s.length - 1) {
      const f = s[i] ? d / s[i] : 0;
      return [pts[i][0] + (pts[i + 1][0] - pts[i][0]) * f, pts[i][1] + (pts[i + 1][1] - pts[i][1]) * f];
    }
    d -= s[i];
  }
  return pts[pts.length - 1];
};
const wfD = (pts: Pt[]) => "M " + pts.map((p) => p.join(" ")).join(" L ");

const WF_AVX = 158;
const WF_CARD = { x: 548, w: 214, h: 196 };
const WF_BOX = { x: 888, y: 720, s: 296 };
const WF_LANE = [300, 720, 1080];
const WF_PATHS: Record<string, Pt[]> = {
  aeCard: [[236, 300], [441, 300]],
  merCard: [[236, 720], [441, 720]],
  desCard: [[236, 1080], [441, 1080]],
  topBox: [[655, 300], [888, 300], [888, 572]],
  midBox: [[655, 720], [740, 720]],
  botBox: [[655, 1080], [888, 1080], [888, 868]],
};

// ── loop clock ──
function useLoopTime(duration: number) {
  const [t, setT] = useState(0);
  useEffect(() => {
    let raf = 0;
    const start = performance.now();
    const tick = (now: number) => {
      setT(((now - start) / 1000) % duration);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [duration]);
  return t;
}

